insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('economics:3-4-price-stability:exam:7f8c3202', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'exam', 'mcq', 1, '{"num": "Q24", "question": "When prices are rising, it is ALWAYS true that:", "options": ["most people are becoming richer", "the cost of living is rising", "the level of unemployment is rising", "the standard of living is falling"], "hint": "The word is ALWAYS. Rising prices might coincide with the other three, but only one MUST follow by definition. If wages rise faster than prices, is the standard of living really falling?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<p><strong>Answer: B — the cost of living is rising</strong></p>\n<ul>\n<li>Rising prices mean the cost of living rises by definition. The others are only SOMETIMES true: if wages rise faster than prices, real incomes and living standards can still improve, and unemployment need not rise at all.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-4-price-stability:mcq:bbdefce0', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'mcq', 'mcq', 1, '{"question": "Inflation is best defined as...", "options": ["A sustained rise in the general level of prices over time", "An increase in the money supply", "A fall in the value of exports", "A rise in the price of one good"]}'::jsonb, '{"answer": 0, "explain": "Inflation is a sustained rise in the GENERAL price level, which means the purchasing power of money falls. A single good''s price rising is not inflation."}'::jsonb),
('economics:3-4-price-stability:mcq:3817fd8c', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'mcq', 'mcq', 1, '{"question": "A nominal value is one which...", "options": ["Has been adjusted for inflation", "Has not been adjusted for taxation", "Has not been adjusted for inflation", "Has been adjusted for taxation"]}'::jsonb, '{"answer": 2, "explain": "Nominal = the raw money figure. REAL is the one adjusted for inflation to show purchasing power."}'::jsonb),
('economics:3-4-price-stability:mcq:6a465408', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'mcq', 'mcq', 1, '{"question": "Which is the best definition of price stability?", "options": ["Prices never change at all", "Inflation remains constant", "Prices increase at an acceptable low rate", "A sustained rise in the general price level"]}'::jsonb, '{"answer": 2, "explain": "Price stability means low, predictable price rises around the 2% target. ''Inflation remains constant'' is wrong — it could be constant at 20%, which is not stable prices."}'::jsonb),
('economics:3-4-price-stability:mcq:3d1518f3', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'mcq', 'mcq', 1, '{"question": "Nominal interest is 4% and inflation is 2%. The real interest rate is...", "options": ["2%", "4%", "6%", "-2%"]}'::jsonb, '{"answer": 0, "explain": "Real = nominal − inflation = 4 − 2 = 2%. Your savings only grow 2% in terms of what they can actually buy."}'::jsonb),
('economics:3-4-price-stability:mcq:961cc761', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'mcq', 'mcq', 1, '{"question": "Inflation is 2.6% and the nominal interest rate on debt is 1.6%. The real interest rate is...", "options": ["1%", "-4.2%", "-1%", "4.2%"]}'::jsonb, '{"answer": 2, "explain": "1.6 − 2.6 = −1%. A NEGATIVE real rate means inflation erodes the debt faster than interest accrues — good news for the borrower."}'::jsonb),
('economics:3-4-price-stability:mcq:b9e61a43', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'mcq', 'mcq', 1, '{"question": "Which statement about the CPI is NOT correct?", "options": ["It is measured every month", "It only measures the price of goods", "It uses a system of weighting", "It measures what an average family spends money on"]}'::jsonb, '{"answer": 1, "explain": "CPI covers goods AND services. The other three statements are all true of the CPI."}'::jsonb),
('economics:3-4-price-stability:mcq:d9c0e9b7', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'mcq', 'mcq', 1, '{"question": "A £45 monthly contract faces 4% inflation in year one and 5% in year two. Its price at the end is...", "options": ["£49.14", "£46.80", "£49.05", "£47.25"]}'::jsonb, '{"answer": 0, "explain": "Apply each rate in turn: £45 × 1.04 = £46.80, then £46.80 × 1.05 = £49.14. Adding 9% in one step gives £49.05 — the trap."}'::jsonb),
('economics:3-4-price-stability:mcq:762e06cb', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'mcq', 'mcq', 1, '{"question": "If the rate of inflation is decreasing but still positive, the price level will...", "options": ["Become negative", "Fall", "Stay the same", "Rise"]}'::jsonb, '{"answer": 3, "explain": "A positive rate means prices are still rising — just more slowly than before. Only a NEGATIVE rate makes the price level fall."}'::jsonb),
('economics:3-4-price-stability:mcq:2f21f524', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'mcq', 'mcq', 1, '{"question": "Which is a consequence of inflation for PRODUCERS?", "options": ["An increase in menu costs", "An increase in the purchasing power of money", "An increase in shoe leather costs", "Real incomes may fall"]}'::jsonb, '{"answer": 0, "explain": "Menu costs — repeatedly changing price lists — fall on producers. Shoe leather costs and falling real incomes hit consumers, and inflation REDUCES purchasing power."}'::jsonb),
('economics:3-4-price-stability:mcq:b86fa44b', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'mcq', 'mcq', 1, '{"question": "Under which circumstances would it be best to be a lender?", "options": ["Nominal interest 2%, inflation 5%", "Nominal interest 7%, inflation 4%", "Nominal interest 5%, inflation 1%", "Nominal interest 0%, inflation 0%"]}'::jsonb, '{"answer": 2, "explain": "A lender wants the highest REAL return: 5 − 1 = +4%, beating 7 − 4 = +3%. The higher nominal rate is not the better deal — the trap."}'::jsonb),
('economics:3-4-price-stability:tf:e2548257', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'tf', 'tf', 1, '{"question": "If the inflation rate falls from 8% to 0.3%, prices have fallen."}'::jsonb, '{"answer": false, "explain": "0.3% is still POSITIVE, so prices are still rising — just far more slowly. Only a negative rate means the price level actually falls."}'::jsonb),
('economics:3-4-price-stability:tf:dab1c88a', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'tf', 'tf', 1, '{"question": "''Inflation remains constant'' is a good definition of price stability."}'::jsonb, '{"answer": false, "explain": "Inflation could be constant at 20% a year, which is not stable prices at all. Price stability means prices rise at an acceptably LOW rate, around the 2% target."}'::jsonb),
('economics:3-4-price-stability:tf:7608bb18', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'tf', 'tf', 1, '{"question": "The CPI includes the prices of exports."}'::jsonb, '{"answer": false, "explain": "CPI tracks what UK CONSUMERS buy. Exports are bought by foreigners, so they''re excluded — as are government spending and firms'' machinery."}'::jsonb),
('economics:3-4-price-stability:tf:9ed03a7c', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'tf', 'tf', 1, '{"question": "Inflation benefits debtors and harms savers."}'::jsonb, '{"answer": true, "explain": "Inflation erodes the real value of what borrowers owe, but also erodes the real value of savings. The caveat: high inflation often brings higher interest rates, which can wipe out the borrower''s gain."}'::jsonb),
('economics:3-4-price-stability:tf:9f62fe6c', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'tf', 'tf', 1, '{"question": "Governments try to reduce inflation to zero."}'::jsonb, '{"answer": false, "explain": "They target about 2%, not zero. A small amount of inflation is helpful because it lets firms adjust prices — and zero inflation usually means the economy isn''t growing."}'::jsonb),
('economics:3-4-price-stability:tf:da27eaf6', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'tf', 'tf', 1, '{"question": "A 3% pay rise when inflation is 5% means real income has fallen."}'::jsonb, '{"answer": true, "explain": "Prices rose faster than pay, so the money buys less than before. Nominal income rose but REAL income fell by about 2%."}'::jsonb),
('economics:3-4-price-stability:tf:cddb7225', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'tf', 'tf', 1, '{"question": "Menu costs are a consequence of inflation for consumers."}'::jsonb, '{"answer": false, "explain": "Menu costs fall on PRODUCERS, who must keep reprinting price lists and relabelling shelves. Shoe leather costs are the consumer equivalent."}'::jsonb),
('economics:3-4-price-stability:tf:c558c2f3', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'tf', 'tf', 1, '{"question": "Inflation is entirely bad for the government."}'::jsonb, '{"answer": false, "explain": "It''s mixed. The government gains as a net debtor (inflation cuts the real value of its debt) and collects more VAT and income tax — but pays more on public sector wages and index-linked benefits."}'::jsonb),
('economics:3-4-price-stability:learn:5af16233', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'learn', 'mcq', 1, '{"readingTitle": "Inflation, price stability, and real vs nominal", "reading": "<p><strong>Inflation is a sustained rise in the general level of prices over time.</strong> As prices rise, a given amount of money buys less — the <strong>purchasing power</strong> of money falls.</p>\n<h4>Price stability — learn the precise wording</h4>\n<ul>\n<li><strong>Price stability is when the general price level grows at a low rate</strong>, such as the UK government''s target of <strong>2% per year</strong>. Two elements = 2 marks; \"prices don''t go up\" scores 1.</li>\n<li>Careful: \"inflation remains constant\" is NOT price stability — inflation could be constant at 20% a year. This is a real MCQ distractor.</li>\n<li>Governments do NOT try to eliminate inflation entirely. A small amount is helpful, because it lets firms adjust their prices over time.</li>\n</ul>\n<h4>Real vs nominal — the distinction the whole topic runs on</h4>\n<ul>\n<li><strong>Nominal</strong> = the actual money figure, <strong>NOT adjusted for inflation</strong>.</li>\n<li><strong>Real</strong> = adjusted for inflation, showing what the money can actually buy.</li>\n<li><strong>Real income:</strong> a 2% pay rise with 4% inflation is a <strong>2% FALL in real income</strong> — prices rose faster than pay.</li>\n<li><strong>Real interest rate = nominal − inflation.</strong> 4% interest with 2% inflation gives a real return of 2%. It can go <strong>negative</strong>: 1.6% nominal with 2.6% inflation = <strong>−1%</strong>.</li>\n</ul>\n<h4>Who wins and who loses</h4>\n<ul>\n<li><strong>Debtors (borrowers) GAIN</strong> — inflation erodes the real value of both what they owe and the interest on it. Caveat: high inflation often brings higher interest rates, which can wipe out the gain for variable-rate mortgage holders.</li>\n<li><strong>Savers LOSE</strong> — the real value of their savings is eroded. Worst for those relying on savings with no new income, e.g. pensioners.</li>\n</ul>", "question": "A worker gets a 2% pay rise when inflation is 4%. What has happened to their real income?", "options": ["It has fallen by about 2%", "It is unchanged", "It has risen by 6%", "It has risen by 2%"]}'::jsonb, '{"answer": 0, "explain": "Real income = nominal adjusted for inflation. Prices rose 4% but pay only 2%, so their money buys about 2% less — a fall in real income despite a nominal rise."}'::jsonb),
('economics:3-4-price-stability:learn:8ad37b09', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'learn', 'mcq', 1, '{"readingTitle": "Measuring inflation — the CPI", "reading": "<p>The UK measures inflation with the <strong>Consumer Price Index (CPI)</strong> — get all three words right; \"customer price index\" is a real MCQ distractor.</p>\n<h4>How the CPI works</h4>\n<ul>\n<li>It tracks the changing cost of a representative <strong>\"basket of goods and services\"</strong> that a typical household buys.</li>\n<li>Prices are collected <strong>monthly</strong>, from a variety of store types across roughly <strong>140 UK locations</strong>, plus online and phone — so it reflects prices faced across the country.</li>\n<li>It uses a system of <strong>weighting</strong>, so items households spend more on count for more. Food and non-alcoholic beverages is by far the largest of the 24 categories.</li>\n<li>The basket <strong>changes over time</strong> to track what people actually buy. In 2022 it added meat-free sausages, canned pulses, sports bras and antibacterial wipes — and removed doughnuts, men''s suits and coal.</li>\n</ul>\n<h4>What CPI does and does NOT include — all real MCQs</h4>\n<ul>\n<li>✅ Goods <strong>AND services</strong> — saying it \"only measures goods\" is false.</li>\n<li>✅ Things a household buys, e.g. children''s clothes.</li>\n<li>❌ <strong>Exports</strong> — they are bought by foreigners, not UK consumers.</li>\n<li>❌ Government spending, and machinery bought by firms.</li>\n<li>❌ It is a representative BASKET, not \"all goods and services in the UK\".</li>\n</ul>\n<h4>Applying an inflation rate</h4>\n<ul>\n<li>Apply each year''s rate <strong>one after the other</strong>, not added together. £45 with 4% then 5% inflation → £45 × 1.04 = £46.80, then £46.80 × 1.05 = <strong>£49.14</strong>. Adding 9% in one step gives £49.05 — the wrong answer.</li>\n</ul>", "question": "Which is included in the UK''s CPI?", "options": ["The price of exports", "The price of a machine bought by a company", "The price of children''s clothes", "Government spending on education"]}'::jsonb, '{"answer": 2, "explain": "CPI tracks the basket bought by typical UK consumers. Exports go to foreigners; government spending and firms'' capital machinery aren''t household purchases."}'::jsonb),
('economics:3-4-price-stability:learn:93f2ed1b', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'learn', 'mcq', 1, '{"readingTitle": "The causes of inflation", "reading": "<p>Two primary causes — you must be able to name and explain both.</p>\n<h4>1. Demand-pull inflation</h4>\n<ul>\n<li>Caused by <strong>excess demand</strong> that supply cannot rise to meet, so prices are bid up.</li>\n<li>More likely when the economy is near <strong>full employment</strong>, because firms cannot easily hire the extra workers needed to supply more.</li>\n<li>Triggers: a rise in C, I, G or (X−M); a fall in interest rates; an increase in the money supply or quantitative easing.</li>\n</ul>\n<h4>2. Cost-push inflation</h4>\n<ul>\n<li>Caused by <strong>rising costs</strong> for firms — raw materials, fuel, power — so they will not supply the same output at the old price.</li>\n<li>Example: the war in Ukraine sharply raised gas, oil and grain prices, and firms passed those costs on.</li>\n<li>Watch for the productivity version: a <strong>10% pay rise with only 6% productivity growth</strong> raises the labour cost of each unit → cost-push inflation.</li>\n</ul>\n<h4>The wage-price spiral — a ready-made analysis chain</h4>\n<ul>\n<li>1. General prices rise, so the cost of living increases → 2. Workers demand higher wages → 3. Firms pay more, so their costs rise → 4. Firms raise prices to cover those costs → 5. Back to step 1.</li>\n<li>Wages are typically a firm''s biggest expense, so this vicious cycle can keep generating inflation unless it is brought under control.</li>\n</ul>", "question": "Workers get a 10% pay rise but productivity rises only 6%. The most likely result is...", "options": ["A fall in consumer confidence", "An increase in consumer debt", "A fall in government tax revenue", "An increase in cost-push inflation"]}'::jsonb, '{"answer": 3, "explain": "Pay is rising faster than output per worker, so the labour cost of each unit produced rises. Firms pass that on as higher prices — cost-push inflation."}'::jsonb),
('economics:3-4-price-stability:learn:99e034ac', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'learn', 'mcq', 1, '{"readingTitle": "The consequences of inflation", "reading": "<p>The spec asks you to evaluate consequences for <strong>consumers, producers, savers and the government</strong> — know each group separately, because questions name one.</p>\n<h4>For consumers</h4>\n<ul>\n<li><strong>Real incomes may fall</strong> — most workers get a below-inflation pay rise, so their standard of living drops.</li>\n<li><strong>The rich/poor gap WIDENS</strong> — high-skill workers in short supply can negotiate above-inflation rises; those on the minimum wage or benefits cannot.</li>\n<li><strong>Falling consumer confidence</strong> — uncertainty pushes people to save rather than spend and to delay big purchases.</li>\n<li><strong>Shoe leather costs</strong> — the time and effort spent shopping around comparing prices.</li>\n</ul>\n<h4>For producers</h4>\n<ul>\n<li><strong>Higher input costs → lower profits</strong> — the simplest and strongest chain.</li>\n<li><strong>Menu costs</strong> — repeatedly changing price lists, websites and shelf labels costs staff time and money.</li>\n<li><strong>Falling producer confidence</strong> — firms delay investment. Sellers of big-ticket items (cars, furniture) suffer most as consumers postpone.</li>\n<li><strong>Industrial conflict</strong> — pay disputes lead to strikes; UK inflation drove the most strikes since the 1970s.</li>\n</ul>\n<h4>For the government — genuinely mixed</h4>\n<ul>\n<li><strong>Gains:</strong> as a net debtor, inflation cuts the real value of its debt; and tax revenue rises automatically, since VAT and income tax are percentages of prices and wages.</li>\n<li><strong>Costs:</strong> higher public sector pay (it employs over 3.5 million people); index-linked benefits and the state pension''s triple lock; and instability that dries up growth.</li>\n</ul>\n<p><strong>The key evaluation lever:</strong> inflation is bad for most people but <strong>worse for some than others</strong>, and it depends on the SIZE of the rate, whether it is positive or negative, and how LONG it lasts.</p>", "question": "Why does high inflation tend to widen the gap between rich and poor?", "options": ["Rich people pay more tax", "Inflation only affects savings", "High-skill workers can negotiate above-inflation pay rises; those on benefits cannot", "Prices rise faster for luxuries"]}'::jsonb, '{"answer": 2, "explain": "Workers whose skills are in high demand and short supply can bargain for above-inflation rises. Minimum-wage workers and benefit claimants have no such power, so their real incomes fall further."}'::jsonb),
('economics:3-4-price-stability:misc:382de837', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Inflation fell from 8.1% to 0.3%, so prices went down.\"</p><p><strong>✅ The correct idea:</strong> This is the single most-tested trap in 3.4, and it appears in at least four separate questions. A FALLING inflation rate that is still POSITIVE means prices are still RISING — just more slowly. Prices only fall when the rate goes NEGATIVE. On the real paper, only Countries T (−0.5%) and Z (−0.1%) saw the price level decrease; Country W''s fall from 8.1% to 0.3% still meant rising prices. The same applies to Q13(a): between August 2013 and February 2015 UK inflation fell towards 0.2%, but the price LEVEL rose the whole time — it just rose at a decreasing rate. The examiners noted candidates ''did not understand the difference between price level and inflation'' or answered by describing only the changes in inflation.</p>", "question": "A country''s inflation falls from 8.1% to 0.3%. What happened to its price level?", "options": ["It fell sharply", "It stayed exactly the same", "It rose, but much more slowly", "It became negative"]}'::jsonb, '{"answer": 2, "explain": "0.3% is positive, so prices still rose — just far more slowly. A falling RATE is not falling PRICES. Only a negative rate means the level falls."}'::jsonb),
('economics:3-4-price-stability:misc:9a3fb4ca', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"The chart shows Chile''s inflation was lowest in 2009, so prices were lowest in 2009 too.\"</p><p><strong>✅ The correct idea:</strong> These are two different things, and the examiners reported candidates ''were unsure about the difference between price level and inflation rate''. Because Chile''s inflation rate is POSITIVE in every year on the chart, prices ROSE every single year — so the price LEVEL was lowest at the very START of the period, in 2006. The CPI rate bottomed out separately, in 2009, when it dipped to about 0.4%. So the answers are: prices lowest = 2006; CPI lowest = 2009. The test: if the rate never goes below zero, the level only ever goes up, so the lowest level is always the first year shown.</p>", "question": "Chile''s inflation is positive every year from 2006–2019, bottoming at 0.4% in 2009. Prices were at their LOWEST level in...", "options": ["2009", "2014", "2019", "2006"]}'::jsonb, '{"answer": 3, "explain": "Positive inflation every year means prices rose every year, so the LEVEL is lowest at the start (2006). 2009 is only where the RATE was lowest."}'::jsonb),
('economics:3-4-price-stability:misc:9352fdf4', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"£45 with 4% then 5% inflation is £45 plus 9% = £49.05.\"</p><p><strong>✅ The correct idea:</strong> You cannot add the rates. Each year''s inflation applies to the ALREADY-INFLATED price, so you must apply them one after the other. £45 × 1.04 = £46.80 (end of year one), then £46.80 × 1.05 = £49.14 (end of year two). The examiners spelled this out: it ''required candidates completing two steps of calculation''. The difference looks small here (£49.14 vs £49.05) but the method matters — and £49.05 is deliberately offered as option C to catch anyone who adds. The same logic applies to any compounding: rates multiply, they don''t add.</p>", "question": "£45 faces 4% inflation then 5% inflation. The correct answer is...", "options": ["£49.14 — apply 4% then 5% to the new figure", "£47.25 — apply 5% only", "£46.80 — apply 4% only", "£49.05 — add 9% to £45"]}'::jsonb, '{"answer": 0, "explain": "Inflation compounds: £45 × 1.04 = £46.80, then × 1.05 = £49.14. The second year''s 5% applies to £46.80, not to the original £45."}'::jsonb),
('economics:3-4-price-stability:misc:c218d74a', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Price stability means inflation stays constant.\"</p><p><strong>✅ The correct idea:</strong> The examiners flagged ''C'' (inflation remains constant) as a common misconception on this exact MCQ, and explained why it''s wrong: inflation could be CONSTANT at a very high rate — say 20% every year — and that is obviously not stable prices. Price stability means the general price level grows at an ACCEPTABLY LOW rate, such as the UK government''s 2% target. A second version of the same error confuses price stability with EQUALITY (a fair distribution of income), which is a completely different macroeconomic objective. And note the third trap: price stability does NOT mean zero inflation — governments deliberately target about 2%, because a little inflation helps firms adjust prices.</p>", "question": "Why is ''inflation remains constant'' a poor definition of price stability?", "options": ["Inflation could be constant at a very high rate, e.g. 20%", "Inflation is never constant", "It is the definition of deflation", "Constant inflation means prices fall"]}'::jsonb, '{"answer": 0, "explain": "The examiners'' own explanation: constant inflation at a high rate is not stable prices. Stability means a LOW rate, around the 2% target."}'::jsonb),
('economics:3-4-price-stability:misc:825b98a2', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Inflation is bad for the government — end of story.\"</p><p><strong>✅ The correct idea:</strong> The consequences for government are genuinely MIXED, and the mark scheme rewards both sides. Costs: more spending on index-linked pensions and universal credit, more on public sector wages (it employs over 3.5 million people), and more strikes if it can''t agree pay rises. But the gains are real: as a net debtor, inflation cuts the REAL value of the government''s debt — the extract itself says it is persistently NEGATIVE inflation that would raise the real value of debt above nominal. Chile''s government paid a real interest rate of −1% in 2019, meaning inflation shrank the debt faster than interest accrued. Tax revenue also rises automatically, since VAT and income tax are percentages of prices and wages. Evaluate on how HIGH inflation is, whether it''s positive or negative, and how LONG it lasts.</p>", "question": "Which is a genuine BENEFIT of inflation for a government?", "options": ["The real value of its debt falls", "It spends more on index-linked pensions", "Strikes become more likely", "Public sector workers demand higher pay"]}'::jsonb, '{"answer": 0, "explain": "As a net debtor, the government gains: inflation erodes the real value of its debt, and tax revenue rises automatically. The other three are costs."}'::jsonb),
('economics:3-4-price-stability:tips:db52761e', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'tips', 'mcq', 1, '{"readingTitle": "definition — Definitions: two elements, every time", "reading": "<p>The examiners were explicit: \"candidates who answered this question well had learnt a PRECISE definition.\" Each of these needs TWO elements:</p>\n<ul>\n<li><strong>Price stability</strong> = the general price level grows at a LOW rate (1) + such as the government''s 2% target (1). \"Prices do not go up\" = 1 mark.</li>\n<li><strong>Inflation</strong> = a sustained rise in the GENERAL price level over time — and it''s worth stating in an ''Analyse'' answer, since knowledge IS credited there.</li>\n<li><strong>Nominal</strong> = not adjusted for inflation. <strong>Real</strong> = adjusted for inflation.</li>\n<li><strong>Two macroeconomic objectives</strong> (other than price stability): low unemployment, economic growth, balanced current account, stable exchange rate. <strong>Do NOT write \"controlling inflation\"</strong> — the mark scheme explicitly refuses it.</li>\n</ul>", "question": "For ''other than price stability, state two macroeconomic objectives'', which answer is explicitly NOT accepted?", "options": ["Low unemployment", "A balanced current account", "Economic growth", "Controlling inflation"]}'::jsonb, '{"answer": 3, "explain": "The mark scheme says: ''Do NOT accept price stability or controlling inflation'' — they''re the same objective the question excluded."}'::jsonb),
('economics:3-4-price-stability:tips:fe88e63c', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'tips', 'mcq', 1, '{"readingTitle": "calculation — Calculations: compound it, and sign it", "reading": "<p>Three rules cover every calculation here:</p>\n<ul>\n<li><strong>Inflation compounds — apply rates one at a time.</strong> £45 × 1.04 × 1.05 = £49.14, NOT £45 + 9%.</li>\n<li><strong>Real = nominal − inflation.</strong> 1.6% − 2.6% = −1%. The mark scheme gives the 1st mark for ''1'' and the <strong>2nd mark ONLY if BOTH the negative sign AND the % sign</strong> are present.</li>\n<li><strong>Best deal for a lender</strong> = highest REAL return, not highest nominal. 5% with 1% inflation (+4%) beats 7% with 4% inflation (+3%).</li>\n</ul>", "question": "You calculate a real interest rate of −1%. To get both marks you must include...", "options": ["Only the % sign", "The working, but signs are optional", "Just the figure 1", "Both the negative sign (or word) and the % sign"]}'::jsonb, '{"answer": 3, "explain": "The mark scheme is explicit: 1st mark for ''1'', then the 2nd mark ONLY if both the negative sign and the percentage sign are given."}'::jsonb),
('economics:3-4-price-stability:tips:4d2352d9', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'tips', 'mcq', 1, '{"readingTitle": "data — Data questions: separate the RATE from the LEVEL", "reading": "<p>Every data question on this paper tests one idea — and it is the topic''s biggest trap.</p>\n<ul>\n<li><strong>If the rate is positive, the level is RISING.</strong> A falling positive rate = prices rising more slowly. Only a negative rate = prices falling.</li>\n<li><strong>So the price LEVEL is lowest in the FIRST year shown</strong> whenever the rate never goes negative — hence \"prices lowest = 2006\" while \"CPI lowest = 2009\".</li>\n<li><strong>Two elements for 2 marks:</strong> \"the price level increased (1) because inflation stayed positive, but at a decreasing rate (1)\".</li>\n<li><strong>Real value of savings:</strong> falls, because inflation is always positive → purchasing power falls.</li>\n</ul>", "question": "For ''what happened to the price level between Aug 2013 and Feb 2015?'', what earns both marks?", "options": ["The price level fell", "Inflation fell from 2.7% to 0.3%", "Inflation was low", "It rose because inflation stayed positive, but at a decreasing rate"]}'::jsonb, '{"answer": 3, "explain": "Describing only the change in inflation misses the question, which asks about the price LEVEL. You need the rise (1) plus the decreasing rate (1)."}'::jsonb),
('economics:3-4-price-stability:tips:d2d36424', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — Analyse & Evaluate: keep it simple, name the group", "reading": "<p>The examiners'' most useful comment on this paper: <strong>\"The strongest answers were often quite SIMPLE and had clear chains of reasoning.\"</strong></p>\n<ul>\n<li><strong>Analyse inflation → producers:</strong> the winning chain is input prices rise → costs of production rise → profits fall. Add menu costs and shoe leather costs. Complex answers often \"missed key links… or did not fully link back to an effect on producers\".</li>\n<li><strong>Name the group.</strong> Menu costs = producers. Shoe leather + falling real incomes = consumers. Debt erosion + tax revenue = government. Questions specify one.</li>\n<li><strong>Evaluate consequences for the government:</strong> genuinely two-sided — costs (index-linked benefits, public sector pay) vs gains (real debt falls, tax revenue rises). Judge on how high, how long, and whether positive or negative.</li>\n<li><strong>Evaluate supply-side costs:</strong> use the extract''s built-in contradiction — cutting direct taxes boosts incentives BUT \"could also lead to rising inflation\".</li>\n</ul>", "question": "For ''analyse how inflation may affect producers'', the examiners said the strongest answers were...", "options": ["The ones quoting the most data", "The most complex and detailed", "The ones with a balanced conclusion", "Quite simple, with clear chains of reasoning"]}'::jsonb, '{"answer": 3, "explain": "They noted simple, clearly reasoned chains (costs rise → profits fall) beat complex answers that missed links or failed to link back to producers."}'::jsonb),
('economics:3-4-price-stability:fib:3fd2ec65', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'fib', 'fib', 2, '{"question": "Inflation is a sustained rise in the ___B1___ price level, which means the ___B2___ power of money falls.", "blankOptions": {"B1": ["Demand", "real", "-1", "general"], "B2": ["Index", "purchasing", "cost", "minus"]}}'::jsonb, '{"blanks": {"B1": "general", "B2": "purchasing"}}'::jsonb),
