('economics:3-4-price-stability:fib:5e8e1a5e', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'fib', 'fib', 2, '{"question": "If the inflation rate is falling but still positive, prices are still ___B1___ — only a ___B2___ rate makes the price level fall.", "blankOptions": {"B1": ["rising", "cost", "basket", "minus"], "B2": ["negative", "weighting", "general", "stability"]}}'::jsonb, '{"blanks": {"B1": "rising", "B2": "negative"}}'::jsonb),
('economics:3-4-price-stability:match:d0ed6d55', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Inflation”?", "options": ["The general price level growing at a low rate, e.g. the 2% target", "A sustained rise in the general level of prices over time", "A negative inflation rate — the general price level actually falls", "How much a given amount of money can actually buy"]}'::jsonb, '{"answer": 1, "explain": "“Inflation” means: A sustained rise in the general level of prices over time"}'::jsonb),
('economics:3-4-price-stability:match:a7e6eeaf', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Price stability”?", "options": ["A negative inflation rate — the general price level actually falls", "The general price level growing at a low rate, e.g. the 2% target", "How much a given amount of money can actually buy", "The raw money figure, not adjusted for inflation"]}'::jsonb, '{"answer": 1, "explain": "“Price stability” means: The general price level growing at a low rate, e.g. the 2% target"}'::jsonb),
('economics:3-4-price-stability:match:348c4e42', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Deflation”?", "options": ["How much a given amount of money can actually buy", "The raw money figure, not adjusted for inflation", "A figure adjusted for inflation, showing what it can buy", "A negative inflation rate — the general price level actually falls"]}'::jsonb, '{"answer": 3, "explain": "“Deflation” means: A negative inflation rate — the general price level actually falls"}'::jsonb),
('economics:3-4-price-stability:match:4c0dcee1', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Purchasing power”?", "options": ["The raw money figure, not adjusted for inflation", "A figure adjusted for inflation, showing what it can buy", "How much a given amount of money can actually buy", "Consumer Price Index — tracks a weighted basket of goods and services"]}'::jsonb, '{"answer": 2, "explain": "“Purchasing power” means: How much a given amount of money can actually buy"}'::jsonb),
('economics:3-4-price-stability:match:34499155', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Nominal value”?", "options": ["The raw money figure, not adjusted for inflation", "A figure adjusted for inflation, showing what it can buy", "Consumer Price Index — tracks a weighted basket of goods and services", "Excess demand that supply cannot rise to meet bids prices up"]}'::jsonb, '{"answer": 0, "explain": "“Nominal value” means: The raw money figure, not adjusted for inflation"}'::jsonb),
('economics:3-4-price-stability:match:a949959a', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Real value”?", "options": ["Consumer Price Index — tracks a weighted basket of goods and services", "Excess demand that supply cannot rise to meet bids prices up", "A figure adjusted for inflation, showing what it can buy", "Rising costs of production are passed on as higher prices"]}'::jsonb, '{"answer": 2, "explain": "“Real value” means: A figure adjusted for inflation, showing what it can buy"}'::jsonb),
('economics:3-4-price-stability:match:92c024dc', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “CPI”?", "options": ["Excess demand that supply cannot rise to meet bids prices up", "Consumer Price Index — tracks a weighted basket of goods and services", "Rising costs of production are passed on as higher prices", "Prices rise, wages rise to match, costs rise, prices rise again"]}'::jsonb, '{"answer": 1, "explain": "“CPI” means: Consumer Price Index — tracks a weighted basket of goods and services"}'::jsonb),
('economics:3-4-price-stability:match:74e4bb13', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Demand-pull inflation”?", "options": ["Excess demand that supply cannot rise to meet bids prices up", "Rising costs of production are passed on as higher prices", "Prices rise, wages rise to match, costs rise, prices rise again", "The cost to producers of repeatedly changing price lists"]}'::jsonb, '{"answer": 0, "explain": "“Demand-pull inflation” means: Excess demand that supply cannot rise to meet bids prices up"}'::jsonb),
('economics:3-4-price-stability:match:41b8a4dd', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Cost-push inflation”?", "options": ["Prices rise, wages rise to match, costs rise, prices rise again", "The cost to producers of repeatedly changing price lists", "The time and effort spent shopping around comparing prices", "Rising costs of production are passed on as higher prices"]}'::jsonb, '{"answer": 3, "explain": "“Cost-push inflation” means: Rising costs of production are passed on as higher prices"}'::jsonb),
('economics:3-4-price-stability:match:6ac065f7', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Wage-price spiral”?", "options": ["Prices rise, wages rise to match, costs rise, prices rise again", "The cost to producers of repeatedly changing price lists", "The time and effort spent shopping around comparing prices", "The nominal interest rate minus the rate of inflation"]}'::jsonb, '{"answer": 0, "explain": "“Wage-price spiral” means: Prices rise, wages rise to match, costs rise, prices rise again"}'::jsonb),
('economics:3-4-price-stability:match:e46348d3', 'economics', 'economics:3-4-price-stability', '3.4 Price Stability', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Menu costs”?", "options": ["The time and effort spent shopping around comparing prices", "The nominal interest rate minus the rate of inflation", "The cost to producers of repeatedly changing price lists", "A sustained rise in the general level of prices over time"]}'::jsonb, '{"answer": 2, "explain": "“Menu costs” means: The cost to producers of repeatedly changing price lists"}'::jsonb),
